// ══ 전공별 탐구주제 추천 (가이드북 기반) ══
// 계열 판별 함수
function getMajorType(major) {
  const m = major || "";
  if (/의예|의학|치의|한의|약학|간호|수의|보건|의생명/.test(m)) return "의학";
  if (/물리|천문|지구과학|지질|대기|해양|지리/.test(m)) return "지구물리";
  if (/화학공|재료|고분자|섬유|에너지공|환경공|나노|신소재/.test(m)) return "화학공학";
  if (/기계|항공|자동차|로봇|우주/.test(m)) return "기계물리";
  if (/전기|전자|반도체|통신|정보통신/.test(m)) return "전기전자";
  if (/컴퓨터|소프트웨어|인공지능|데이터|정보|사이버/.test(m)) return "컴퓨터";
  if (/생명|생물|농업|식품|바이오/.test(m)) return "생명";
  if (/화학(?!공)/.test(m)) return "화학";
  if (/수학|통계/.test(m)) return "수학";
  if (/경제|경영|회계|무역|금융/.test(m)) return "사회";
  if (/사회|사회학|심리|복지|행정|법학|정치/.test(m)) return "사회";
  if (/국어|영어|문학|언어|철학|역사|교육|사범/.test(m)) return "인문";
  return "자연";
}

function getRecommendedTopics(major) {
  let bestKey = null, bestScore = 0;
  for (const [key, kws] of Object.entries(MAJOR_KW)) {
    const score = kws.filter(kw => major.includes(kw) || key.includes(major) || major.includes(key)).length + (key === major ? 10 : 0);
    if (score > bestScore) { bestScore = score; bestKey = key; }
  }
  const matchedKey = Object.keys(MAJOR_KW).find(k => major.includes(k) || k.includes(major)) || bestKey;
  if (!matchedKey) {
    // MAJOR_KW 매칭 실패 시에도 국어·수학·사회·영어·공통 주제는 기본 표시
    const majorTypeF = getMajorType(major);
    const isSciF = !["사회","인문","교육"].some(t => majorTypeF.includes(t));
    return {
      생명과학1: [], 화학1: [], 물리학1: [], 지구과학1: [], 과학탐구실험: [],
      국어:      KOR_TOPICS.slice(0, 5),
      수학:      MATH_TOPICS.slice(isSciF ? 0 : 50, isSciF ? 5 : 55),
      통합사회:  SOC_TOPICS.slice(isSciF ? 44 : 0, isSciF ? 49 : 5),
      영어:      ENG_TOPICS.slice(0, 5),
      공통탐구:  COMMON_TOPICS.slice(0, 5),
      majorType: majorTypeF, majorName: null,
    };
  }
  const kws = MAJOR_KW[matchedKey];
  const majorType = getMajorType(major);

  // 계열별 표시 과목 결정
  const showBio     = ["의학","생명","화학공학","화학","자연"].includes(majorType);
  const showChem    = ["의학","생명","화학공학","화학","자연","기계물리","전기전자"].includes(majorType);
  const showPhysics = ["지구물리","화학공학","기계물리","전기전자","컴퓨터","자연"].includes(majorType);
  const showEarth   = ["지구물리","자연"].includes(majorType);
  const showKor     = true; // 전 계열
  const showMath    = true; // 전 계열
  const showSoc     = true; // 전 계열

  // 모든 과탐/융합 DB 통합 (모듈 레벨 캐시 사용)
  const allExpTopics = ALL_EXP_TOPICS;

  // 국어·수학·사회·영어: 전공 계열별 확장 키워드로 필터링 → 부족하면 계열별 구간 보완
  const showEng = true;
  const engCount = 5;

  // 계열별 확장 키워드 (전공 kws + 계열 공통)
  // 계열별 확장 필터 키워드
  // 계열별 특화 확장 키워드 (범용어 "공학","기술" 제거 → 기계공학 혼입 방지)
  // 계열별 특화 필터 (모호한 단어 제외 - "공정"→공정거래 혼입, "산업"→산업혁명 혼입 방지)
  const majorTypeKws = {
    "화학공학":  ["화학반응","고분자","촉매","나노소재","화학공학","연료전지","탄소중립","화학물질","플라스틱분해","광촉매","바이오연료","수소생산"],
    "기계물리":  ["열역학","유체역학","동역학","항공","로봇공학","엔진","마찰","진동해석"],
    "전기전자":  ["전기회로","반도체","전자기","광전자","통신공학","센서설계"],
    "컴퓨터":   ["알고리즘","머신러닝","딥러닝","데이터구조","네트워크프로토콜","암호화"],
    "의학":     ["면역반응","세포신호","유전자발현","약물대사","임상시험","진단키트"],
    "생명과학":  ["효소반응","세포분열","유전자편집","대사경로","미생물배양","생태계"],
    "지구물리":  ["대기순환","해양조류","지진파","화산폭발","기후변화모델","천체관측"],
  };
  const typeKws = majorTypeKws[majorType] || [];
  // sciKws: 전공 kws + 계열 특화어. "산업","공정","기술" 같은 모호한 단어 제외
  const sciKws = [...new Set([...kws, ...typeKws])];
  const humKws = [...kws, "언어","문학","역사","사회","문화","철학","법","경제","정치","교육","심리","인문","예술","미디어","복지"];
  const isSci  = !["사회","인문","교육"].some(t => majorType.includes(t));
  const extKws = isSci ? sciKws : humKws;

  // 필터 후 부족하면 전공 키워드만으로 재시도, 그래도 부족하면 계열 구간 fallback
  // 이공계/인문계 광범위 fallback 키워드
  const sciFallbackKws = ["과학","기술","환경","에너지","실험","화학","물리","생물","수학","데이터","인공지능","기후"];
  const humFallbackKws = ["언어","사회","문화","역사","철학","경제","정치","교육","심리","예술","문학","법"];

  const filterOrSlice = (db, extKw, baseKw, fallbackStart, n) => {
    // 1차: 전공 특화 + 계열 확장 키워드
    const f1 = db.filter(t => extKw.some(kw => t.includes(kw))).slice(0, n);
    if (f1.length >= 3) return f1.slice(0, n);
    // 2차: 전공 기본 키워드(MAJOR_KW)
    const f2 = db.filter(t => baseKw.some(kw => t.includes(kw))).slice(0, n);
    if (f2.length >= 3) return f2;
    // 3차: 계열별 광범위 fallback
    const fbKws = isSci ? sciFallbackKws : humFallbackKws;
    const f3 = db.filter(t => fbKws.some(kw => t.includes(kw))).slice(fallbackStart, fallbackStart + n);
    if (f3.length >= 3) return f3;
    // 4차: fallbackStart 구간 순서대로 (부족하면 앞에서 채움) — 항상 n개 보장
    const f4 = db.slice(fallbackStart, fallbackStart + n);
    if (f4.length >= n) return f4;
    // 5차: DB 앞에서부터 채워서 반드시 n개 반환
    return db.slice(0, n);
  };

  const korTopics  = showKor  ? filterOrSlice(KOR_TOPICS,  extKws, kws, 0,   8) : [];
  const mathTopics = showMath ? filterOrSlice(MATH_TOPICS, extKws, kws, 7,   8) : [];
  const socTopics  = showSoc  ? filterOrSlice(SOC_TOPICS,  extKws, kws, isSci?44:0, 8) : [];
  const engTopics  = showEng  ? filterOrSlice(ENG_TOPICS,  extKws, kws, 0,   8) : [];

  // 공통 주제: 전공 키워드 매칭 시도, 없으면 상위 5개 제공
  const commonFiltered = COMMON_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0, 5);
  const commonTopics = commonFiltered.length >= 3 ? commonFiltered : COMMON_TOPICS.slice(0, 5);

  return {
    생명과학1:     showBio     ? (BIO_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8).length>=3 ? BIO_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8) : BIO_TOPICS.slice(0,8)) : [],
    화학1:         showChem    ? (CHEM_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8).length>=3 ? CHEM_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8) : CHEM_TOPICS.slice(0,8)) : [],
    물리학1:       showPhysics ? (PHYSICS_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8).length>=3 ? PHYSICS_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8) : PHYSICS_TOPICS.slice(0,8)) : [],
    지구과학1:     showEarth   ? (EARTH_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8).length>=3 ? EARTH_TOPICS.filter(t => kws.some(kw => t.includes(kw))).slice(0,8) : EARTH_TOPICS.slice(0,8)) : [],
    과학탐구실험:  (allExpTopics.filter(t => kws.some(kw => t.includes(kw))).slice(0,5).length>=3 ? allExpTopics.filter(t => kws.some(kw => t.includes(kw))).slice(0,5) : allExpTopics.slice(0,5)),
    국어:          korTopics,
    수학:          mathTopics,
    통합사회:      socTopics,
    영어:          engTopics,
    공통탐구:      commonTopics,
    majorType,
    majorName: matchedKey,
  };
}

// 계열별 평가 포인트 (KEDI 명칭 기준)
const 계열_EVAL_TIPS = {
  의약계열:  "【서울대 의대 합격 패턴】① 생명과학·화학 전 과목 1등급 유지 + 과탐2(물리2·화학2·생명2) 이수 ② 의생명캠프·실험동아리에서 PCR·전기영동·단백질 정량 등 실제 실험 경험 기록 ③ 수학(미적분·확률통계)을 의학 문제에 직접 연결 — 혈류속도·심전도·진단검사 모델링 ④ 교과 개념을 실제 질환·치료법·의료기술에 연결하는 심화 세특 ⑤ 의료윤리·공공보건·사회적 맥락 탐구 병행 ⑥ 꾸준한 봉사·멘토링으로 인성 증명",
  자연계열:  "수학적 모델링 활용, 실험 설계·변인 통제, 심화 개념 적용, 타 자연과학 분야와의 융합, 연구자적 호기심과 논리적 추론 과정",
  공학계열:  "공학적 문제해결 과정(설계→제작→개선), 수학·물리 원리의 현실 적용, AI·반도체·모빌리티 등 신기술 연계, 팀 프로젝트·메이커 활동 경험",
  사회계열:  "데이터·통계 분석, 사회현상 다각적 해석, 이론과 현실 연결, 정책·제도적 함의 도출, 경제·법·행정 분야 교과 연계 탐구",
  인문계열:  "텍스트 비판적 분석, 인문학적 통찰력, 언어·문학·역사·철학·심리학과 타 학문과의 융합, 문화·사회 현상에 대한 깊이 있는 해석",
  교육계열:  "교육학적 이론 적용, 학습자 발달 이해, 교육 현장 연계, 사회적 교육 이슈 탐구, 교과 교육학 관련 심화 활동",
};


// ══ 탐구주제 추천 컴포넌트 ══
function RecommendTab({ major, curriculum, currBadge, onAiResult, apiKey }) {
  const guideData = findGuideMatch(major);
  const [loading, setLoading] = useState(false);
  const [aiTopics, setAiTopics] = useState(null);
  const [copied, setCopied] = useState(null);

  const guidebookRec = useMemo(() => getRecommendedTopics(major), [major]);

  const getAiRecommend = async () => {
    setLoading(true); setAiTopics(null);
    try {
      const bioSample = guidebookRec.생명과학1.slice(0,6).join(", ");
      const chemSample = guidebookRec.화학1.slice(0,6).join(", ");
      const 계열 = getCategory열(major);
      const exampleCases = (SETECH_EXAMPLES[계열]||[]).slice(0,4).join('\n');
      const evalTip = 계열_EVAL_TIPS[계열] || "";
      const isMedical = 계열 === "의약계열";
      const medicalPattern = isMedical ? `
[서울대 의대 합격생 공통 패턴]
- 수학 교과에서 의학 문제 직접 연결: 혈류속도·심전도·확률통계 진단검사 모델링
- 생명과학에서 실험 기반 세특: PCR·전기영동·단백질 정량·면역 메커니즘
- 화학에서 약물·분자구조 연계: 나노의약·분자오비탈·반응속도
- 교과 개념 → 실제 질환명·치료법으로 연결 (단순 개념 설명 NO)
- 영어·국어에서도 의학 주제 선택 (의료윤리·공중보건·감염병 대응)` : "";
      const prompt = `[아펙스 컨설팅팀 세특 탐구주제 추천 요청]
[${계열} 실제 합격 세특 사례]
${exampleCases}
${medicalPattern}

목표전공: ${major} (${계열}) / 교육과정: ${curriculum==="2022"?"2022개정(고1·고2)":"2015개정(고3·N수)"}

[세특 가이드북 관련 주제 예시]
생명과학1: ${bioSample}
화학1: ${chemSample}

[${계열} 평가 핵심 포인트]
${evalTip}

위를 바탕으로 ${major} 지원자에게 실제로 도움이 되는 차별화된 탐구주제 3개를 추천해주세요.
- 고등학교 수준에서 실행 가능해야 함
- 전공 적합성이 명확히 드러나는 주제 (교과 개념 → 실제 질환·기술 연결 필수)
- 기존에 많이 쓰이지 않는 창의적 주제 우선
- 의약계열은 반드시 실험·수식·임상 연계 중 하나 포함

JSON만 출력(마크다운 없이):
{"topics":[{"title":"탐구주제명","subject":"관련과목","type":"실험/이론/융합","tip":"이 주제가 ${major}에 왜 효과적인지 한 줄","level":"기본/심화/최심화"}]}`;

      const res = await fetch("/api/claude", {
        method:"POST", headers:{"Content-Type":"application/json","x-api-key":apiKey,"anthropic-version":"2023-06-01"},
        body: JSON.stringify({
          model:"claude-sonnet-4-5-20250929", max_tokens:1500,
          system:`당신은 모든에듀 아펙스 컨설팅팀 소속 학생부종합전형 세특 전문 컨설턴트입니다. ${계열} 계열 전문가로서 실제 입시에서 효과적인 탐구주제를 추천합니다. 순수 JSON만 출력하세요.`,
          messages:[{role:"user",content:prompt}]
        })
      });
      const data = await res.json();
      const parsed = JSON.parse((data.content?.[0]?.text||"").replace(/```json|```/g,"").trim());
      const tops=(parsed.topics||[]).slice(0,3); setAiTopics(tops); if(onAiResult) onAiResult(tops);
    } catch(e) { setAiTopics([]); if(onAiResult) onAiResult([]); }
    finally { setLoading(false); }
  };

  // 탭 열리면 자동 AI 호출
  useEffect(() => {
    if (!aiTopics && !loading) {
      getAiRecommend();
    }
  }, []);

  const copyTopic = (title) => {
    navigator.clipboard?.writeText(title).catch(()=>{});
    setCopied(title); setTimeout(()=>setCopied(null), 1800);
  };

  const TYPE_COLOR = {
    실험:{bg:"#EFF6FF",c:"#1565C0",b:"#BFDBFE"},
    이론:{bg:"#F5F3FF",c:"#6D28D9",b:"#DDD6FE"},
    융합:{bg:"#FFF7ED",c:"#C2410C",b:"#FED7AA"}
  };
  const LVL_DOT = { 기본:"#22C55E", 심화:"#F59E0B", 최심화:"#EF4444" };

  return (
    <div style={{flex:1,overflow:"auto",background:"#F8FAFC",padding:"24px 20px"}}>
      <div style={{maxWidth:900,margin:"0 auto",display:"flex",flexDirection:"column",gap:18}}>

        {/* 헤더 */}
        <div style={{background:"#fff",borderRadius:16,border:"1px solid #E5E7EB",overflow:"hidden",boxShadow:"0 1px 8px rgba(0,0,0,0.05)"}}>
          <div style={{background:"linear-gradient(135deg,#1565C0,#1976D2)",padding:"20px 24px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:16,flexWrap:"wrap"}}>
            <div>
              <div style={{color:"rgba(255,255,255,0.6)",fontSize:10,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:6}}>실제 합격생 세특 주제 기반</div>
              <div style={{color:"#fff",fontSize:20,fontWeight:900,letterSpacing:"-0.02em"}}>{major} 탐구주제 추천</div>
              <div style={{color:"rgba(255,255,255,0.6)",fontSize:11,marginTop:5,display:"flex",gap:14,flexWrap:"wrap"}}>
                {guidebookRec.생명과학1.length > 0 && <span>📗 생명과학1 {guidebookRec.생명과학1.length}개</span>}
                {guidebookRec.화학1.length > 0 && <span>🧪 화학1 {guidebookRec.화학1.length}개</span>}
                {guidebookRec.물리학1?.length > 0 && <span>⚡ 물리학1 {guidebookRec.물리학1.length}개</span>}
                {guidebookRec.지구과학1?.length > 0 && <span>🌍 지구과학1 {guidebookRec.지구과학1.length}개</span>}
                {guidebookRec.과학탐구실험?.length > 0 && <span>🔬 과학탐구실험 {guidebookRec.과학탐구실험.length}개</span>}
                {guidebookRec.국어?.length > 0 && <span>📖 국어 {guidebookRec.국어.length}개</span>}
                {guidebookRec.수학?.length > 0 && <span>📐 수학 {guidebookRec.수학.length}개</span>}
                {guidebookRec.통합사회?.length > 0 && <span>🌏 통합사회 {guidebookRec.통합사회.length}개</span>}
                {guidebookRec.영어?.length > 0 && <span>🔤 영어 {guidebookRec.영어.length}개</span>}
                {guidebookRec.공통탐구?.length > 0 && <span>💡 공통 {guidebookRec.공통탐구.length}개</span>}
                {getCategory열(major) && <span style={{background:"rgba(255,255,255,0.15)",padding:"1px 8px",borderRadius:10}}>📂 {getCategory열(major)}</span>}
                <span>· {currBadge.label}</span>
              </div>
            </div>
            <button onClick={getAiRecommend} disabled={loading}
              style={{padding:"11px 20px",background:loading?"rgba(255,255,255,0.15)":"#fff",border:"none",borderRadius:10,color:loading?"rgba(255,255,255,0.6)":"#1565C0",fontWeight:800,fontSize:13,cursor:loading?"not-allowed":"pointer",fontFamily:"inherit",display:"flex",alignItems:"center",gap:7,boxShadow:loading?"none":"0 2px 10px rgba(0,0,0,0.12)",transition:"all 0.2s",whiteSpace:"nowrap"}}>
              {loading ? "⏳ 분석 중..." : "🔄 다시 추천받기"}
            </button>
          </div>
        </div>

        {/* 로딩 상태 */}
        {loading && (
          <div style={{background:"#fff",borderRadius:16,border:"1px solid #E5E7EB",padding:"40px",textAlign:"center",boxShadow:"0 1px 8px rgba(0,0,0,0.05)"}}>
            <div style={{fontSize:32,marginBottom:12}}>⏳</div>
            <div style={{fontSize:14,color:"#1565C0",fontWeight:700}}>AI가 전공 특화 탐구주제를 분석 중입니다...</div>
            <div style={{fontSize:12,color:"#6B7280",marginTop:6}}>잠시만 기다려주세요 (10~20초)</div>
          </div>
        )}

        {/* 에러/빈배열 처리 */}
        {!loading && aiTopics && aiTopics.length === 0 && (
          <div style={{background:"#FFF7ED",borderRadius:16,border:"1px solid #FED7AA",padding:"24px",textAlign:"center"}}>
            <div style={{fontSize:14,color:"#92400E",fontWeight:700,marginBottom:8}}>⚠️ AI 추천 생성 실패</div>
            <div style={{fontSize:12,color:"#B45309"}}>API 오류가 발생했습니다. 아래 버튼을 눌러 다시 시도하세요.</div>
          </div>
        )}

        {/* 아펙스 추천 결과 */}
        {!loading && aiTopics && aiTopics.length > 0 && (
          <div style={{background:"#fff",borderRadius:16,border:"1px solid #E5E7EB",overflow:"hidden",boxShadow:"0 1px 8px rgba(0,0,0,0.05)"}}>
            <div style={{padding:"14px 20px",borderBottom:"1px solid #F3F4F6",display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:30,height:30,borderRadius:9,background:"linear-gradient(135deg,#1565C0,#1976D2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>⭐</div>
              <div>
                <div style={{fontWeight:800,fontSize:14,color:"#111827"}}>아펙스 컨설팅팀 추천</div>
                <div style={{fontSize:11,color:"#9CA3AF",marginTop:1}}>{major} 맞춤 전략 탐구주제 · 클릭 시 복사</div>
              </div>
              {aiTopics.length > 0 && <span style={{marginLeft:"auto",background:"#EFF6FF",color:"#1565C0",border:"1px solid #BFDBFE",fontSize:10,fontWeight:700,padding:"3px 10px",borderRadius:20}}>3개</span>}
            </div>
            {aiTopics.length === 0 ? (
              <div style={{padding:"40px 24px",textAlign:"center"}}>
                <div style={{fontSize:30,marginBottom:10}}>😔</div>
                <div style={{fontSize:13,fontWeight:600,color:"#374151"}}>추천 결과를 불러오지 못했어요</div>
                <div style={{fontSize:11,color:"#9CA3AF",marginTop:4}}>버튼을 다시 눌러주세요</div>
              </div>
            ) : (
              <div style={{padding:"16px 20px",display:"flex",flexDirection:"column",gap:10}}>
                {aiTopics.map((t,i)=>{
                  const tc = TYPE_COLOR[t.type]||TYPE_COLOR["융합"];
                  const dot = LVL_DOT[t.level]||"#9CA3AF";
                  const isC = copied===t.title;
                  return (
                    <div key={i} onClick={()=>copyTopic(t.title)}
                      style={{borderRadius:12,border:"1.5px solid "+(isC?"#86EFAC":"#F0F0F0"),background:isC?"#F0FFF4":"#FAFAFA",padding:"14px 16px",cursor:"pointer",transition:"all 0.15s",display:"flex",gap:14,alignItems:"flex-start"}}
                      onMouseOver={e=>{if(!isC){e.currentTarget.style.background="#F0F9FF";e.currentTarget.style.borderColor="#BFDBFE";}}}
                      onMouseOut={e=>{if(!isC){e.currentTarget.style.background="#FAFAFA";e.currentTarget.style.borderColor="#F0F0F0";}}}>
                      <div style={{width:30,height:30,borderRadius:10,background:isC?"#22C55E":"linear-gradient(135deg,#1565C0,#1976D2)",color:"#fff",fontSize:13,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,transition:"background 0.2s"}}>
                        {isC?"✓":i+1}
                      </div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontWeight:700,fontSize:13,color:"#111827",marginBottom:7,lineHeight:1.4}}>{t.title}</div>
                        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:8,alignItems:"center"}}>
                          <span style={{background:tc.bg,color:tc.c,border:"1px solid "+tc.b,padding:"2px 8px",borderRadius:6,fontSize:10,fontWeight:700}}>{t.type}</span>
                          <span style={{display:"flex",alignItems:"center",gap:3,fontSize:10,color:"#6B7280",fontWeight:600}}>
                            <span style={{width:6,height:6,borderRadius:"50%",background:dot,display:"inline-block"}}></span>{t.level}
                          </span>
                          <span style={{fontSize:10,color:"#C5CFD8"}}>· {t.subject}</span>
                        </div>
                        <div style={{fontSize:11,color:"#4B5563",lineHeight:1.7,background:"#fff",border:"1px solid #F3F4F6",borderRadius:8,padding:"8px 11px"}}>💡 {t.tip}</div>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {/* 아펙스컨설팅팀 - 전공 맞춤 권장 과목 */}
        {guideData && (
          <div style={{background:"#fff",border:"1.5px solid #BBF7D0",borderRadius:16,padding:"18px 20px",boxShadow:"0 2px 12px rgba(0,0,0,0.05)",marginBottom:16}}>
            <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14}}>
              <span style={{fontSize:18}}>🗺️</span>
              <div>
                <div style={{fontSize:14,fontWeight:800,color:"#15803D"}}>전공 맞춤 권장 과목 (아펙스컨설팅팀)</div>
                <div style={{fontSize:10,color:"#9CA3AF"}}>학생부종합전형 대비 과목 선택 가이드</div>
              </div>
            </div>
            {guideData.c && guideData.c.length > 0 && (
              <div style={{marginBottom:12,display:"flex",flexDirection:"column",gap:6}}>
                {guideData.c.map((comp,i)=>(
                  <div key={i} style={{display:"flex",alignItems:"flex-start",gap:8,background:"#F0FDF4",borderRadius:8,padding:"8px 12px",border:"1px solid #BBF7D0"}}>
                    <span style={{color:"#15803D",fontWeight:700,flexShrink:0}}>✓</span>
                    <span style={{fontSize:12,color:"#374151",lineHeight:1.6}}>{comp}</span>
                  </div>
                ))}
              </div>
            )}
            {guideData.s && guideData.s.length > 0 && (
              <div>
                <div style={{fontSize:11,fontWeight:700,color:"#15803D",marginBottom:8}}>📚 권장 이수 과목</div>
                <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                  {guideData.s.map((subj,i)=>(
                    <span key={i} style={{background:"#F0FDF4",color:"#15803D",border:"1.5px solid #86EFAC",borderRadius:20,padding:"4px 12px",fontSize:11,fontWeight:700}}>{subj}</span>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* 가이드북 기반 2열 */}
        <div style={{background:"#fff",borderRadius:16,border:"1px solid #E5E7EB",overflow:"hidden",boxShadow:"0 1px 8px rgba(0,0,0,0.05)"}}>
          <div style={{padding:"14px 20px",borderBottom:"1px solid #F3F4F6",background:"#F8FAFC",display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:16}}>📚</span>
            <div>
              <div style={{fontWeight:800,fontSize:13,color:"#111827"}}>실제 합격생 세특 주제 기반 추가 추천</div>
              <div style={{fontSize:11,color:"#6B7280",marginTop:2}}>실제 합격생 세특 주제 + 탐구주제 DB 기반 과목별 탐구주제</div>
            </div>
          </div>
          <div style={{padding:"16px 20px"}}>
          {/* 과목군별 그룹 헤더 */}
          {[
            {group:"🔬 과학", color:"#2E7D32", bg:"#F0FFF4", border:"#BBF7D0", sections:[
              {key:"생명과학1",   icon:"📗",topics:guidebookRec.생명과학1||[],   color:"#2E7D32",light:"#F0FFF4",border:"#A7F3D0"},
              {key:"화학1",       icon:"🧪",topics:guidebookRec.화학1||[],       color:"#1565C0",light:"#EFF6FF",border:"#BFDBFE"},
              {key:"물리학1",     icon:"⚡",topics:guidebookRec.물리학1||[],     color:"#7C3AED",light:"#F5F3FF",border:"#DDD6FE"},
              {key:"지구과학1",   icon:"🌍",topics:guidebookRec.지구과학1||[],   color:"#B45309",light:"#FFFBEB",border:"#FDE68A"},
              {key:"과학탐구실험",icon:"🔬",topics:guidebookRec.과학탐구실험||[],color:"#0F766E",light:"#F0FDFA",border:"#99F6E4"},
            ]},
            {group:"📖 국어", color:"#DC2626", bg:"#FEF2F2", border:"#FECACA", sections:[
              {key:"국어",        icon:"📖",topics:guidebookRec.국어||[],        color:"#DC2626",light:"#FEF2F2",border:"#FECACA"},
            ]},
            {group:"📐 수학", color:"#1D4ED8", bg:"#EFF6FF", border:"#BFDBFE", sections:[
              {key:"수학",        icon:"📐",topics:guidebookRec.수학||[],        color:"#1D4ED8",light:"#EFF6FF",border:"#BFDBFE"},
            ]},
            {group:"🌏 사회", color:"#D97706", bg:"#FFFBEB", border:"#FDE68A", sections:[
              {key:"통합사회",    icon:"🌏",topics:guidebookRec.통합사회||[],    color:"#D97706",light:"#FFFBEB",border:"#FDE68A"},
            ]},
            {group:"🔤 영어", color:"#0277BD", bg:"#E0F2FE", border:"#BAE6FD", sections:[
              {key:"영어",        icon:"🔤",topics:guidebookRec.영어||[],        color:"#0277BD",light:"#E0F2FE",border:"#BAE6FD"},
            ]},
            {group:"💡 공통", color:"#6D28D9", bg:"#F5F3FF", border:"#DDD6FE", sections:[
              {key:"공통탐구",    icon:"💡",topics:guidebookRec.공통탐구||[],    color:"#6D28D9",light:"#F5F3FF",border:"#DDD6FE"},
            ]},
          ].map(grp => {
            const activeSections = grp.sections.filter(s => s.topics.length > 0);
            if (activeSections.length === 0) return null;
            return (
              <div key={grp.group} style={{marginBottom:18}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10,paddingBottom:6,borderBottom:"2px solid "+grp.border}}>
                  <span style={{fontSize:14,fontWeight:800,color:grp.color}}>{grp.group}</span>
                  <span style={{background:grp.bg,color:grp.color,border:"1px solid "+grp.border,fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:12}}>
                    {activeSections.reduce((a,s)=>a+s.topics.length,0)}개 주제
                  </span>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
                {activeSections.map(sec=>(
                  <div key={sec.key} style={{background:"#fff",borderRadius:14,border:"1px solid #E5E7EB",overflow:"hidden",boxShadow:"0 1px 6px rgba(0,0,0,0.04)"}}>
                    <div style={{padding:"11px 16px",borderBottom:"1px solid #F3F4F6",display:"flex",alignItems:"center",gap:8}}>
                      <span style={{fontSize:14}}>{sec.icon}</span>
                      <span style={{fontWeight:800,fontSize:12,color:"#111827"}}>{sec.key}</span>
                      <span style={{marginLeft:"auto",background:sec.light,color:sec.color,border:"1px solid "+sec.border,fontSize:10,fontWeight:700,padding:"2px 8px",borderRadius:16}}>{sec.topics.length}개</span>
                    </div>
                    <div style={{maxHeight:320,overflow:"auto"}}>
                      {sec.topics.map((t,i)=>{
                        const isC = copied===t;
                        return (
                          <div key={i} onClick={()=>copyTopic(t)}
                            style={{padding:"9px 16px",borderBottom:"1px solid #F9FAFB",display:"flex",alignItems:"center",gap:9,cursor:"pointer",background:isC?sec.light:"#fff",transition:"background 0.1s"}}
                            onMouseOver={e=>{if(!isC)e.currentTarget.style.background="#F8FAFC";}}
                            onMouseOut={e=>{if(!isC)e.currentTarget.style.background="#fff";}}>
                            <span style={{width:18,height:18,borderRadius:5,background:isC?sec.color:sec.light,color:isC?"#fff":sec.color,fontSize:9,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                              {isC?"✓":i+1}
                            </span>
                            <span style={{fontSize:11,color:"#374151",fontWeight:500,lineHeight:1.5,flex:1}}>{t}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
                </div>
              </div>
            );
          }).filter(Boolean)}
          </div>{/* padding div */}
        </div>{/* card wrapper */}

        <div style={{textAlign:"center",color:"#C5CFD8",fontSize:10,paddingBottom:4}}>
          클릭하면 클립보드에 복사됩니다 · 실제 합격생 세특 주제 + 탐구주제 DB 기반
        </div>
      </div>
    </div>
  );
}
