function findGuideMatch(major) {
  if (!major || !GUIDE_DB) return null;
  if (GUIDE_DB[major]) return GUIDE_DB[major];
  const keys = Object.keys(GUIDE_DB);
  const partial = keys.find(k => major.includes(k) || k.includes(major));
  if (partial) return GUIDE_DB[partial];
  const stem = major.replace(/(학과|학부|전공|과|부)$/, '');
  const stemMatch = keys.find(k => stem.length > 2 && (k.includes(stem) || k.replace(/(학과|학부|전공|과|부)$/, '').includes(stem)));
  return stemMatch ? GUIDE_DB[stemMatch] : null;
}
function findDeptMatch(major) {
  if (!major || !CASE_DB) return null;
  // Exact match
  if (CASE_DB[major]) return { key: major, data: CASE_DB[major] };
  // Partial match
  const keys = Object.keys(CASE_DB);
  const exact = keys.find(k => k === major || major === k);
  if (exact) return { key: exact, data: CASE_DB[exact] };
  const partial = keys.find(k => major.includes(k) || k.includes(major));
  if (partial) return { key: partial, data: CASE_DB[partial] };
  // Try stem match (remove 과/학과/부 suffix variants)
  const stem = major.replace(/(학과|학부|전공|과|부)$/, '');
  const stemMatch = keys.find(k => k.includes(stem) || (stem.length > 2 && k.replace(/(학과|학부|전공|과|부)$/, '').includes(stem)));
  if (stemMatch) return { key: stemMatch, data: CASE_DB[stemMatch] };
  // 추가: 전공명이 키워드로 포함되는 경우 (예: "화학공학" → "화학공학과")
  const kwMatch = keys.find(k => k.replace(/(학과|학부|전공|과|부)$/, '').startsWith(major) || major.startsWith(k.replace(/(학과|학부|전공|과|부)$/, '')));
  if (kwMatch) return { key: kwMatch, data: CASE_DB[kwMatch] };
  return null;
}

function GradeBar({ label, grade, color, maxGrade = 6 }) {
  const pct = grade ? Math.min((parseFloat(grade) / maxGrade) * 100, 100) : 0;
  return (
    <div style={{ marginBottom: 8 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}>
        <span style={{ fontSize: 11, color: '#6B7280', fontWeight: 600 }}>{label}</span>
        <span style={{ fontSize: 12, fontWeight: 700, color }}>{grade ? `${grade}등급` : '데이터 없음'}</span>
      </div>
      <div style={{ background: '#F3F4F6', borderRadius: 6, height: 10, overflow: 'hidden' }}>
        <div style={{ width: `${pct}%`, height: '100%', background: color, borderRadius: 6, transition: 'width 0.6s ease' }} />
      </div>
    </div>
  );
}

