// 전공적합성 매칭 함수 (일치/유사/부족 판정)
function matchKeywords(studentKws, guideKs) {
  if (!guideKs || guideKs.length === 0) return { matched:[], similar:[], missing:[], score:0, level:"" };
  const stuLower = studentKws.map(k => k.toLowerCase());
  const matched = [], similar = [], missing = [];
  guideKs.forEach(gk => {
    const synonyms = SYNONYM_MAP[gk] || [gk];
    // 완전 일치 체크
    const exactHit = synonyms.some(syn => stuLower.some(sk => sk.includes(syn.toLowerCase()) || syn.toLowerCase().includes(sk)));
    if (exactHit) { matched.push(gk); return; }
    // 유사 체크 (부분 포함)
    const partialHit = synonyms.some(syn =>
      stuLower.some(sk => {
        const sl = syn.toLowerCase(); const skl = sk.toLowerCase();
        return sl.length > 2 && skl.length > 2 && (sl.includes(skl.slice(0,Math.min(skl.length,3))) || skl.includes(sl.slice(0,3)));
      })
    );
    if (partialHit) { similar.push(gk); return; }
    missing.push(gk);
  });
  const score = matched.length * 2 + similar.length * 1 - Math.min(missing.length, 2) * 1;
  const level = score >= 6 ? "높음" : score >= 3 ? "보통" : "보완필요";
  return { matched, similar, missing, score, level };
}

